PythonJavaScriptBash <pre><code>import requests

with open('audio.wav', 'rb') as f:
    response = requests.post(
        'http://localhost:4800/api/transcribe',
        files={'audio': f}
    )
    print(response.json()['text'])
</code></pre> <pre><code>const fs = require('fs');
const FormData = require('form-data');
const axios = require('axios');

const form = new FormData();
form.append('audio', fs.createReadStream('recording.wav'));

const response = await axios.post(
  'http://localhost:4800/api/transcribe',
  form,
  { headers: form.getHeaders() }
);
console.log(response.data.text);
</code></pre> <pre><code>curl -X POST http://localhost:4800/api/transcribe \
  -F "audio=@recording.wav" \
  | jq '.text'
</code></pre>

